class Solution {
    public String countOfAtoms(String formula) {
        Stack<int[]> stack = new Stack<>();
        int[] cur = new int[26];
        stack.push(cur);
        int multi = 1;
        for (char c : formula.toCharArray()) {
            if (c == '(') {
                stack.push(cur.clone());
            } else if (c == ')') {
                cur = stack.pop();
                multi = stack.peek()[25];
                for (int i = 0; i < 26; i++) {
                    cur[i] *= multi;
                    stack.peek()[i] += cur[i];
                }
            } else if (Character.isLetter(c)) {
                int i = c - 'A';
                if (Character.isDigit(c)) {
                    multi = multi * (c - '0');
                }
                cur[i] += multi;
                multi = 1;
            }
        }
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 26; i++) {
            if (cur[i] > 0) {
                sb.append((char) ('A' + i));
                if (cur[i] > 1) {
                    sb.append(cur[i]);
                }
            }
        }
        return sb.toString();
    }
}
